   254→    private func exportData() {
   255→        isExporting = true
   256→        exportStatus = ""
   257→
   258→        Task {
   259→            do {
   260→                let docs = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
   261→                let timestamp = ISO8601DateFormatter().string(from: Date()).replacingOccurrences(of: ":", with: "-")
   262→                let dest = docs.appendingPathComponent("souvenir_export_\(timestamp).json")
   263→
   264→                try exportCoreDataToJSON(container: container, to: dest)
   265→
   266→                await MainActor.run {
   267→                    exportURL = dest
   268→                    exportStatus = "✅ Exported \(dest.lastPathComponent)"
   269→                    isExporting = false
   270→                    isSharing = true
   271→                }
   272→            } catch {
   273→                await MainActor.run {
   274→                    exportStatus = "❌ Export failed: \(error.localizedDescription)"
   275→                    isExporting = false
   276→                }
   277→                print("❌ Export failed: \(error)")
   278→            }
   279→        }
   280→    }
