   289→                guard let seedURL = Bundle.main.url(forResource: "seed", withExtension: "json", subdirectory: "SeedData") else {
   290→                    throw ImportError.invalidFormat
   291→                }
   292→
   293→                // Clear existing data
   294→                try await clearAllData()
   295→
   296→                // Import from JSON with seed images
   297→                try await importCoreDataFromJSON(
   298→                    container: container,
   299→                    jsonURL: seedURL,
   300→                    seedImagesFolder: "SeedData/Images"
   301→                )
   302→
   303→                await MainActor.run {
   304→                    // Reset onboarding flags since we're importing data
   305→                    hasSavedFirstSouvenir = true
   306→                    hasPlayedIntro = true
   307→                    importStatus = "✅ Successfully imported seed data"
   308→                    isImporting = false
   309→                }
   310→            } catch {
