   340→    /// Deletes all records via the managed object context so NSPersistentCloudKitContainer
   341→    /// tracks the deletes and propagates them to iCloud.
   342→    private func nukeAllData() {
   343→        nukeStatus = ""
   344→        Task {
   345→            do {
   346→                let ctx = container.viewContext
   347→                try await ctx.perform {
   348→                    ctx.userInfo["svnrSkipDeleteValidation"] = true
   349→                    defer { ctx.userInfo["svnrSkipDeleteValidation"] = nil }
   350→                    // Phase 1: clear all blocking relationships so validateForDelete passes.
   351→                    // • SouvenirEntity throws if hasActiveShares
   352→                    // • ContactEntity throws if primarySouvenir != nil
   353→                    // • PhotoEntity throws if favoritedBySouvenir != nil or is souvenir's only photo
   354→                    let souvenirReq = NSFetchRequest<SouvenirEntity>(entityName: "SouvenirEntity")
   355→                    let souvenirs = try ctx.fetch(souvenirReq)
   356→                    for s in souvenirs {
   357→                        s.favoritePhoto = nil       // unblocks PhotoEntity.validateForDelete
   358→                        s.primaryContact = nil      // unblocks ContactEntity.validateForDelete
   359→                        s.photos = nil              // clears photo→souvenir inverse
   360→                        s.shares = nil              // unblocks SouvenirEntity.validateForDelete
   361→                    }
   362→                    try ctx.save()
   363→
   364→                    // Phase 2: delete everything — validators all pass now.
   365→                    for entityName in ["ShareEntity", "PhotoEntity", "ContactEntity", "SouvenirEntity"] {
   366→                        let req = NSFetchRequest<NSManagedObject>(entityName: entityName)
   367→                        let objects = try ctx.fetch(req)
   368→                        objects.forEach { ctx.delete($0) }
   369→                    }
   370→                    try ctx.save()
   371→                }
   372→                await MainActor.run {
   373→                    hasSavedFirstSouvenir = false
   374→                    hasPlayedIntro = false
   375→                    hasTappedSouvenirButton = false
   376→                    nukeStatus = "✅ All data cleared — CloudKit sync pending"
   377→                }
   378→            } catch {
   379→                await MainActor.run {
   380→                    nukeStatus = "❌ Nuke failed: \(error.localizedDescription)"
   381→                }
   382→            }
   383→        }
   384→    }
   385→
   386→    private func clearAllData() async throws {
   387→        await container.viewContext.perform {
   388→            self.container.viewContext.rollback()
   389→        }
   390→        let entityNames = ["SouvenirEntity", "ContactEntity", "PhotoEntity", "ShareEntity"]
   391→
   392→        for entityName in entityNames {
   393→            let fetchRequest = NSFetchRequest<NSFetchRequestResult>(entityName: entityName)
   394→            let deleteRequest = NSBatchDeleteRequest(fetchRequest: fetchRequest)
   395→
   396→            _ = try await container.viewContext.perform {
   397→                try self.container.viewContext.execute(deleteRequest)
   398→            }
   399→        }
   400→
   401→        try await container.viewContext.perform {
   402→            try self.container.viewContext.save()
   403→        }
   404→    }
   405→}
