   407→/// A debug view to inspect bundle contents at runtime
   408→struct BundleDebugView: View {
   409→    @State private var bundleContents: String = "Inspecting..."
   410→
   411→    var body: some View {
   412→        Section(header: Text("Bundle Contents Inspector")) {
   413→            Text(bundleContents)
   414→                .font(.system(.caption, design: .monospaced))
   415→                .onAppear(perform: inspectBundle)
   416→        }
   417→    }
   418→
   419→    func inspectBundle() {
   420→        let bundleURL = Bundle.main.bundleURL
   421→        var output = "Bundle Path: \(bundleURL.path)\n\n"
   422→
   423→        guard let enumerator = FileManager.default.enumerator(at: bundleURL, includingPropertiesForKeys: nil, options: [.skipsHiddenFiles], errorHandler: nil) else {
   424→            bundleContents = "Failed to create bundle enumerator."
   425→            return
   426→        }
   427→
   428→        var found = false
   429→        for case let fileURL as URL in enumerator {
   430→            let relativePath = fileURL.path.replacingOccurrences(of: bundleURL.path, with: "")
   431→            if relativePath.contains("seed.json") {
   432→                found = true
   433→            }
   434→            output += "\(relativePath)\n"
   435→        }
   436→
   437→        if !found {
   438→            output = "seed.json NOT FOUND IN BUNDLE\n\n" + output
   439→        }
   440→
   441→        bundleContents = output
   442→    }
   443→}
   444→
   445→/// UIKit wrapper for file share sheet (AirDrop/Files/Mail/etc).
   446→struct FileShareSheet: UIViewControllerRepresentable {
   447→    let activityItems: [Any]
   448→    let applicationActivities: [UIActivity]? = nil
   449→
   450→    func makeUIViewController(context: Context) -> UIActivityViewController {
   451→        let vc = UIActivityViewController(activityItems: activityItems, applicationActivities: applicationActivities)
   452→        vc.excludedActivityTypes = [.assignToContact, .print]
   453→        return vc
   454→    }
   455→
   456→    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
   457→}
