import Foundation
import CoreData
@preconcurrency import Contacts
import Combine

// MARK: - Dependencies
// Note: ContactSearchNormalizing protocol and ContactSearchNormalizer struct
// are defined in ServicesContactSearchNormalizer.swift
//
// Note: ContactSearchResult enum is defined in ModelsContactSearchResult.swift
// Note: ContactsSystemService class is defined in ServicesContactsSystemService.swift
// Ensure all these files are included in your Xcode target.

// MARK: - Contact Search Service

/// Service for searching and creating contacts.
public final class ContactSearchService: ObservableObject {
    private let persistenceController: PersistenceController
    private let normalizer: ContactSearchNormalizing

    public init(persistenceController: PersistenceController, normalizer: ContactSearchNormalizing) {
        self.persistenceController = persistenceController
        self.normalizer = normalizer
    }

    public convenience init(viewContext: NSManagedObjectContext) {
        // Legacy init for compatibility - extract persistence controller
        self.init(persistenceController: .shared, normalizer: ContactSearchNormalizer())
    }

    public init(persistenceController: PersistenceController) {
        self.persistenceController = persistenceController
        self.normalizer = ContactSearchNormalizer()
    }

    /// Search existing contacts in Core Data by name.
    public func searchContacts(query: String) async throws -> [ContactEntity] {
        guard !query.isEmpty else {
            return []
        }

        // Use view context directly for simplicity and reliability
        return try await persistenceController.container.viewContext.perform {
            let request = ContactEntity.fetchRequest()

            // Search in all name fields, handling nil values properly
            // Using separate predicates and combining them with OR
            let compositeNamePredicate = NSPredicate(format: "compositeName CONTAINS[cd] %@", query)
            let givenNamePredicate = NSPredicate(format: "givenName CONTAINS[cd] %@", query)
            let familyNamePredicate = NSPredicate(format: "familyName CONTAINS[cd] %@", query)

            request.predicate = NSCompoundPredicate(orPredicateWithSubpredicates: [
                compositeNamePredicate,
                givenNamePredicate,
                familyNamePredicate
            ])

            request.sortDescriptors = [NSSortDescriptor(keyPath: \ContactEntity.givenName, ascending: true)]
            request.fetchLimit = 20

            return try self.persistenceController.container.viewContext.fetch(request)
        }
    }

    /// Search existing contacts by phone (normalizes input to E.164 before matching).
    public func searchContactByPhone(input: String) async throws -> ContactEntity? {
        guard let e164 = normalizer.normalizePhone(input: input) else { return nil }

        return try await persistenceController.container.viewContext.perform {
            let request = ContactEntity.fetchRequest()
            request.predicate = NSPredicate(format: "phoneE164 == %@", e164)
            request.fetchLimit = 1
            return try self.persistenceController.container.viewContext.fetch(request).first
        }
    }

    /// Create a new contact entity (simplified - uses view context).
    /// - Throws: ValidationError if contact validation fails
    public func createContact(
        givenName: String?,
        familyName: String?,
        phone: String?,
        email: String? = nil
    ) async throws -> ContactEntity {
        let normalizer = self.normalizer
        let normalizedPhone = phone.flatMap { normalizer.normalizePhone(input: $0) }
        let validationPhone = normalizedPhone ?? phone

        // Phase 14: Validate contact requirements before creation
        try ValidationService.validateContactRequirements(
            givenName: givenName,
            familyName: familyName,
            phone: validationPhone,
            email: email
        )

        return try await persistenceController.container.viewContext.perform {
            let contact = ContactEntity(context: self.persistenceController.container.viewContext)
            contact.id = UUID()
            contact.givenName = givenName
            contact.familyName = familyName

            // Build composite name for searching - ALWAYS set it if we have any name
            let names = [givenName, familyName].compactMap { $0 }.filter { !$0.isEmpty }
            if !names.isEmpty {
                contact.compositeName = names.joined(separator: " ")
            } else {
                // Fallback: If no names provided, set compositeName to empty string for consistency
                contact.compositeName = ""
            }

            contact.phoneE164 = normalizedPhone
            contact.email = email
            contact.createdAt = Date()
            contact.isPrimaryForSouvenir = false

            try self.persistenceController.container.viewContext.save()

            print("✅ Contact created: \(contact.displayName)")

            return contact
        }
    }

    /// Validate phone format (checks if it can be normalized to E.164).
    public func validatePhone(_ phone: String) -> Bool {
        return normalizer.normalizePhone(input: phone) != nil
    }

    /// Debug: Get all contacts in the database
    public func getAllContacts() async throws -> [ContactEntity] {
        print("🔍 DEBUG: Fetching ALL contacts from database")

        return try await persistenceController.container.viewContext.perform {
            let request = ContactEntity.fetchRequest()
            request.sortDescriptors = [NSSortDescriptor(keyPath: \ContactEntity.createdAt, ascending: false)]

            let results = try self.persistenceController.container.viewContext.fetch(request)
            print("🔍 DEBUG: Found \(results.count) total contacts:")

            for (index, contact) in results.enumerated() {
                print("   \(index + 1). ID: \(contact.id)")
                print("      Given: \(contact.givenName ?? "nil")")
                print("      Family: \(contact.familyName ?? "nil")")
                print("      Composite: \(contact.compositeName ?? "nil")")
                print("      Created: \(contact.createdAt)")
            }

            return results
        }
    }

    // MARK: - Phase 2.5: System Contacts Integration

    /// Search both local contacts AND system contacts, returning unified results.
    /// System contacts that are already imported are filtered out from system results.
    public func searchAllContacts(query: String, includeSystem: Bool = true) async throws -> [ContactSearchResult] {
        var results: [ContactSearchResult] = []

        // 1. Search local Core Data contacts
        let localContacts = try await searchContacts(query: query)
        results.append(contentsOf: localContacts.map { .local($0) })

        // 2. Search system contacts if permission granted and requested
        if includeSystem {
            let systemService = ContactsSystemService()
            if systemService.authorizationStatus() == .authorized {
                let systemContacts = try await systemService.searchContacts(query: query)

                // Filter out contacts already in our local database (by externalIdentifier)
                let systemResults = systemContacts
                    .filter { cnContact in
                        !localContacts.contains(where: { $0.externalIdentifier == cnContact.identifier })
                    }
                    .map { ContactSearchResult.system($0) }

                results.append(contentsOf: systemResults)
            }
        }

        return results
    }

    /// Import a system contact (CNContact) into local Core Data storage.
    /// Links via externalIdentifier for future sync capabilities.
    /// Returns existing ContactEntity if already imported (by externalIdentifier).
    /// - Throws: ValidationError if contact validation fails
    public func importSystemContact(_ cnContact: CNContact) async throws -> ContactEntity {
        let normalizer = self.normalizer

        // Extract contact data for validation
        let givenName = cnContact.givenName.isEmpty ? nil : cnContact.givenName
        let familyName = cnContact.familyName.isEmpty ? nil : cnContact.familyName
        let rawPhoneNumber = cnContact.phoneNumbers.first?.value.stringValue
        let email = cnContact.emailAddresses.first?.value as String?
        let birthdayDate = cnContact.birthday.flatMap { Calendar.current.date(from: $0) }
        let postalAddress = (cnContact.postalAddresses.first { $0.label == CNLabelHome } ?? cnContact.postalAddresses.first)?.value
        let normalizedPhone = rawPhoneNumber.flatMap { normalizer.normalizePhone(input: $0) }

        // System contacts are already validated by iOS - skip strict validation
        // Just log if normalization produced unexpected results
        if let rawPhone = rawPhoneNumber, normalizedPhone == nil {
            print("⚠️ Could not normalize phone '\(rawPhone)' to E.164 format")
        }

        return try await persistenceController.container.viewContext.perform {
            // Bug fix: Check if contact already exists by externalIdentifier
            let request = ContactEntity.fetchRequest()
            request.predicate = NSPredicate(format: "externalIdentifier == %@", cnContact.identifier)
            request.fetchLimit = 1
            if let existing = try self.persistenceController.container.viewContext.fetch(request).first {
                print("✅ Found existing contact for system ID: \(existing.displayName)")
                return existing
            }

            let contact = ContactEntity(context: self.persistenceController.container.viewContext)
            contact.id = UUID()
            contact.givenName = givenName
            contact.familyName = familyName
            contact.externalIdentifier = cnContact.identifier // Link to system contact

            // Build composite name for searching
            let names = [contact.givenName, contact.familyName].compactMap { $0 }.filter { !$0.isEmpty }
            if !names.isEmpty {
                contact.compositeName = names.joined(separator: " ")
            } else {
                contact.compositeName = ""
            }

            // Import first phone number (E.164 normalized)
            if let normalizedPhone = normalizedPhone {
                contact.phoneE164 = normalizedPhone
            }

            // Import first email
            if let email = email {
                contact.email = email
            }

            // Import contact image (prefer full image, fallback to thumbnail)
            if let imageData = cnContact.imageData ?? cnContact.thumbnailImageData {
                contact.imageThumbData = imageData
            }

            if let birthdayDate = birthdayDate {
                contact.birthday = birthdayDate
            }

            if let postalAddress = postalAddress {
                contact.address = CNPostalAddressFormatter.string(from: postalAddress, style: .mailingAddress)
                    .replacingOccurrences(of: "\n", with: ", ")
            }

            contact.createdAt = Date()
            contact.isPrimaryForSouvenir = false

            try self.persistenceController.container.viewContext.save()

            print("✅ Imported system contact: \(contact.displayName)")

            return contact
        }
    }
}

