import Foundation
import CoreData
import Combine

/// Service responsible for creating souvenirs with photos and contacts
public actor SouvenirCaptureService {
    private let persistenceController: PersistenceController
    private let geocodingService: GeocodingService
    private let what3wordsService: What3WordsService
    private let plusCodeService: PlusCodeService

    public init(
        persistenceController: PersistenceController,
        geocodingService: GeocodingService? = nil,
        what3wordsService: What3WordsService? = nil,
        plusCodeService: PlusCodeService? = nil
    ) {
        self.persistenceController = persistenceController
        self.geocodingService = geocodingService ?? GeocodingService(persistenceController: persistenceController)

        // Try to get what3words API key from multiple sources
        let w3wKey: String? = {
            // First, try environment variable (for development)
            if let envKey = ProcessInfo.processInfo.environment["W3W_API_KEY"], !envKey.isEmpty {
                return envKey
            }
            // Then, try Info.plist (for production builds)
            if let plistKey = Bundle.main.object(forInfoDictionaryKey: "What3WordsAPIKey") as? String,
               !plistKey.isEmpty,
               !plistKey.hasPrefix("$(") { // Ignore unresolved build variables
                return plistKey
            }
            return nil
        }()

        self.what3wordsService = what3wordsService ?? What3WordsService(apiKey: w3wKey, persistenceController: persistenceController)
        self.plusCodeService = plusCodeService ?? PlusCodeService(persistenceController: persistenceController)
    }

    /// Create a new souvenir with a photo and contact
    /// - Parameters:
    ///   - photo: Photo metadata (coordinates, timestamp, etc.)
    ///   - contact: Contact entity (must already exist in database)
    ///   - caption: Optional caption for the souvenir
    /// - Returns: The UUID of the created SouvenirEntity
    /// - Throws: ValidationError or SouvenirCaptureError if validation fails
    public func createSouvenir(
        photo: PhotoMetadata,
        contact: ContactEntity,
        caption: String?
    ) async throws -> UUID {
        // Extract contact ID and display name from the managed object context
        // This must be done on the context's queue to be thread-safe
        let contactObjectID = contact.objectID
        let contactContext = contact.managedObjectContext

        let contactID: UUID
        let displayName: String

        if let context = contactContext {
            (contactID, displayName) = try await context.perform {
                guard let contact = try? context.existingObject(with: contactObjectID) as? ContactEntity else {
                    throw SouvenirCaptureError.contactNotFound
                }
                return (contact.id, contact.displayName)
            }
        } else {
            throw SouvenirCaptureError.contactNotFound
        }

        print("📸 Creating souvenir for contact: \(displayName)")

        // Phase 14: Validate inputs before proceeding
        try await validatePhotoMetadata(photo)
        try await validateContact(contactID: contactID)

        let context = persistenceController.newBackgroundContext()

        return try await context.perform {
            // Ensure contact exists in this context
            guard let contactInContext = try self.fetchContact(id: contactID, context: context) else {
                throw SouvenirCaptureError.contactNotFound
            }

            // Phase 14: Validate contact in context
            try ValidationService.validateContact(contactInContext)

            print("📸 Step 1: Creating PhotoEntity")

            // Check if photo already exists (by assetLocalId)
            let photoEntity: PhotoEntity
            if let existingPhoto = try self.fetchPhoto(assetLocalId: photo.assetLocalId, context: context) {
                print("   ℹ️ Using existing photo: \(existingPhoto.id)")
                photoEntity = existingPhoto

                // Phase 14: Validate existing photo
                try ValidationService.validatePhoto(existingPhoto)

                // Phase 14: Check for duplicate photo in souvenir (Rule 15)
                if let existingSouvenir = contactInContext.primarySouvenir, existingSouvenir.deletedAt == nil {
                    if ValidationService.checkDuplicatePhotoInSouvenir(
                        photo: existingPhoto,
                        souvenir: existingSouvenir
                    ) {
                        throw ValidationError.duplicatePhotoInSouvenir
                    }
                }
            } else {
                print("   ℹ️ Creating new photo")
                photoEntity = PhotoEntity(context: context)
                photoEntity.id = UUID()
                photoEntity.assetLocalId = photo.assetLocalId
                photoEntity.timestamp = photo.timestamp
                photoEntity.timezoneID = photo.timezoneID

                // Initialize viewport defaults - start locked (view mode)
                photoEntity.viewportScale = 1.0
                photoEntity.viewportOffsetX = 0.0
                photoEntity.viewportOffsetY = 0.0
                photoEntity.isViewportLocked = true

                // Store coordinates if available
                if let location = photo.location {
                    // Phase 14: Validate coordinates before storing
                    try ValidationService.validateCoordinates(
                        latitude: location.latitude,
                        longitude: location.longitude
                    )
                    photoEntity.latitude = NSNumber(value: location.latitude)
                    photoEntity.longitude = NSNumber(value: location.longitude)
                    print("   📍 Coordinates: \(location.latitude), \(location.longitude)")
                }

                // Phase 14: Validate newly created photo
                try ValidationService.validatePhoto(photoEntity)
            }

            print("📸 Step 2: Creating or updating SouvenirEntity")

            print("   ℹ️ Creating new souvenir")
            let souvenirEntity = SouvenirEntity(context: context)
            souvenirEntity.id = UUID()
            souvenirEntity.caption = caption
            souvenirEntity.createdAt = Date()
            souvenirEntity.updatedAt = Date()
            souvenirEntity.meetTime = photoEntity.timestamp ?? souvenirEntity.createdAt
            if let meetPlace = photo.geocodedAddress?.shortDescription, !meetPlace.isEmpty {
                souvenirEntity.meetPlace = meetPlace
            }

            // Set relationships
            print("📸 Step 3: Linking relationships")
            souvenirEntity.primaryContact = contactInContext
            souvenirEntity.photos = [photoEntity]
            souvenirEntity.favoritePhoto = photoEntity

            // Add contact to photo
            var contacts = photoEntity.contacts ?? Set()
            contacts.insert(contactInContext)
            photoEntity.contacts = contacts

            // Phase 14: Validate newly created souvenir (Rule 6)
            try ValidationService.validateSouvenir(souvenirEntity)

            print("📸 Step 4: Recomputing derived fields")

            // Phase 6: Use the new recomputeDerivedFields method that handles
            // lastLatitude/lastLongitude and favoritePhoto logic
            souvenirEntity.recomputeDerivedFields()

            print("📸 Step 5: Saving context")

            // Phase 14.1: Relationship integrity validation
            try ValidationService.validateRelationshipIntegrity(
                photo: photoEntity,
                contact: contactInContext,
                souvenir: souvenirEntity
            )

            // Save
            try context.save()

            let souvenirID = souvenirEntity.id
            print("✅ Souvenir created successfully: \(souvenirID)")

            // Phase 15.1: Relationship integrity warnings (non-blocking)
            let warnings = ValidationService.relationshipIntegrityWarnings(for: souvenirEntity)
            if !warnings.isEmpty {
                print("⚠️ Relationship warnings: \(warnings.joined(separator: " | "))")
            }

            // Phase 4: Trigger background geocoding if photo has coordinates
            if let lat = photoEntity.latitude?.doubleValue,
               let lon = photoEntity.longitude?.doubleValue,
               !(lat == 0.0 && lon == 0.0) { // Skip invalid (0, 0) coordinates
                let photoID = photoEntity.id
                Task.detached {
                    await self.geocodePhotoInBackground(photoID: photoID)
                }
            }

            return souvenirID
        }
    }

    // MARK: - Background Geocoding (Phase 4)

    /// Geocode a photo in the background without blocking the UI
    private func geocodePhotoInBackground(photoID: UUID) async {
        print("🌍 Starting background geocoding for photo: \(photoID)")

        // Run geocoding and Plus Code generation in parallel
        async let geocodeTask: Void = {
            do {
                _ = try await self.geocodingService.geocodePhotoIfNeeded(photoID: photoID)
            } catch {
                print("⚠️ Geocoding failed (non-fatal): \(error)")
            }
        }()

        async let plusCodeTask: Void = {
            do {
                _ = try await self.plusCodeService.generatePlusCode(photoID: photoID)
            } catch {
                print("⚠️ Plus Code generation failed (non-fatal): \(error)")
            }
        }()

        // Wait for both to complete
        _ = await (geocodeTask, plusCodeTask)
        print("✅ Background geocoding complete for photo: \(photoID)")
    }

    /// Batch geocode all photos that need it (for background task)
    public func geocodeAllPendingPhotos() async throws -> Int {
        print("🌍 Finding photos needing geocoding...")

        let photoIDs = try await geocodingService.findPhotosNeedingGeocode()

        guard !photoIDs.isEmpty else {
            print("✅ No photos need geocoding")
            return 0
        }

        print("🌍 Geocoding \(photoIDs.count) photos...")
        let geocodedCount = await geocodingService.geocodePhotos(photoIDs)

        print("🌍 Converting \(photoIDs.count) photos to what3words...")
        let w3wCount = await what3wordsService.convertPhotos(photoIDs)

        print("➕ Generating Plus Codes for \(photoIDs.count) photos...")
        let plusCodeCount = await plusCodeService.generatePlusCodes(photoIDs)

        print("✅ Batch geocoding complete: \(geocodedCount) geocoded, \(w3wCount) converted to w3w, \(plusCodeCount) Plus Codes generated")

        return geocodedCount
    }

    // MARK: - Validation Methods (Phase 14)

    /// Validate photo metadata before creating souvenir
    /// - Parameter photo: PhotoMetadata to validate
    /// - Throws: ValidationError if validation fails
    private func validatePhotoMetadata(_ photo: PhotoMetadata) async throws {
        // Validate assetLocalId
        guard !photo.assetLocalId.isEmpty else {
            throw ValidationError.missingRequiredField("assetLocalId")
        }

//        // Validate timestamp
//        guard photo.timestamp != nil else {
//            throw ValidationError.missingRequiredField("timestamp")
//        }

        // Validate coordinates if provided
        if let location = photo.location {
            try await MainActor.run {
                try ValidationService.validateCoordinates(
                    latitude: location.latitude,
                    longitude: location.longitude
                )
            }
        }
    }

    /// Validate contact before creating souvenir
    /// - Parameter contactID: ContactEntity identifier
    /// - Throws: ValidationError if validation fails
    private func validateContact(contactID: UUID) async throws {
        let context = persistenceController.container.viewContext
        try await context.perform {
            guard let contactInContext = try self.fetchContact(id: contactID, context: context) else {
                throw SouvenirCaptureError.contactNotFound
            }
            try ValidationService.validateContact(contactInContext)
        }
    }

    /// Validate souvenir creation parameters
    /// - Parameters:
    ///   - photo: PhotoMetadata
    ///   - contactID: ContactEntity identifier
    ///   - context: NSManagedObjectContext
    /// - Throws: ValidationError if validation fails
    private func validateSouvenirCreation(
        photo: PhotoMetadata,
        contactID: UUID,
        context: NSManagedObjectContext
    ) async throws {
        // Validate photo metadata
        try await validatePhotoMetadata(photo)

        // Check if photo already exists and validate within context.perform
        let assetLocalId = photo.assetLocalId
        try await context.perform {
            guard let contactInContext = try self.fetchContact(id: contactID, context: context) else {
                throw SouvenirCaptureError.contactNotFound
            }

            try ValidationService.validateContact(contactInContext)

            // Fetch photo by assetLocalId
            let photoRequest = PhotoEntity.fetchRequest()
            photoRequest.predicate = NSPredicate(format: "assetLocalId == %@", assetLocalId)
            photoRequest.fetchLimit = 1

            guard let existingPhoto = try context.fetch(photoRequest).first else {
                return // Photo doesn't exist yet, no duplicate to check
            }

            // Check if this photo is already in a souvenir with this contact
            let hasDuplicate = (existingPhoto.souvenirs)?.contains(where: {
                $0.deletedAt == nil && $0.primaryContact?.id == contactID
            }) ?? false

            if hasDuplicate {
                throw ValidationError.duplicatePhotoInSouvenir
            }
        }
    }

    // MARK: - Private Helpers

    nonisolated private func fetchContact(id: UUID, context: NSManagedObjectContext) throws -> ContactEntity? {
        let request = ContactEntity.fetchRequest()
        request.predicate = NSPredicate(format: "id == %@", id as CVarArg)
        request.fetchLimit = 1

        return try context.fetch(request).first
    }

    nonisolated private func fetchPhoto(assetLocalId: String, context: NSManagedObjectContext) throws -> PhotoEntity? {
        let request = PhotoEntity.fetchRequest()
        request.predicate = NSPredicate(format: "assetLocalId == %@", assetLocalId)
        request.fetchLimit = 1

        return try context.fetch(request).first
    }
}

// MARK: - Errors

public enum SouvenirCaptureError: LocalizedError {
    case contactNotFound
    case photoLoadFailed
    case saveFailed(Error)
    case validationFailed(ValidationError)

    public var errorDescription: String? {
        switch self {
        case .contactNotFound:
            return "Contact not found in database"
        case .photoLoadFailed:
            return "Failed to load photo metadata"
        case .saveFailed(let error):
            return "Failed to save souvenir: \(error.localizedDescription)"
        case .validationFailed(let validationError):
            return "Validation failed: \(validationError.localizedDescription)"
        }
    }
}

//
//  ServicesShareService.swift
//  souvenir
//
//  Phase 3: Sharing
//  Manages share token creation, validation, and Universal Link generation
//

import Foundation
import CoreData
import CryptoKit
import CloudKit

// MARK: - Share State

/// Derived share state for a souvenir based on its ShareEntity rows.
enum ShareState: Equatable {
    /// No shares exist — this souvenir is local only.
    case localOnly
    /// A share was created but the participant has not yet accepted.
    case pendingInvite
    /// At least one participant has accepted and the share is active.
    case sharedActive
    /// All shares have been revoked or declined.
    case sharedRevoked
}

// MARK: - String Constants

/// Raw string values stored in `ShareEntity.status`.
enum ShareStatus {
    static let pending = "pending"
    static let accepted = "accepted"
    static let declined = "declined"
    static let revoked = "revoked"
}

/// Raw string values stored in `ShareEntity.role`.
enum ShareRole {
    static let owner = "owner"
    static let participant = "participant"
}

// MARK: - Errors

enum ShareError: LocalizedError {
    case shareCreationFailed
    case shareURLUnavailable
    case containerUnavailable

    var errorDescription: String? {
        switch self {
        case .shareCreationFailed: return "Failed to create CloudKit share."
        case .shareURLUnavailable: return "Share URL is not yet available."
        case .containerUnavailable: return "CloudKit container is unavailable."
        }
    }
}

/// Service for creating and validating share tokens
final class ShareService {

    // MARK: - Configuration

    /// Universal Link base URL
    static let baseURL = "https://souvenir.kerry.ink"

    /// App Store link for invite
    static let appStoreURL = "https://apps.apple.com/app/id0000000000" // Replace with actual App Store ID

    /// Default token expiration: 48 hours
    static let defaultExpirationInterval: TimeInterval = 48 * 60 * 60

    /// Warning-only helper for upcoming expiration validation (Phase 15.1 scaffolding)
    func expirationWarning(for share: ShareEntity) -> String? {
        let remaining = share.expiresAt.timeIntervalSinceNow
        if remaining <= 0 {
            return "This share link has expired."
        }
        if remaining < 24 * 60 * 60 {
            let hours = max(1, Int(remaining / 3600))
            return "This share link expires in about \(hours) hours."
        }
        return nil
    }

    /// Token length in bytes (URL-safe base64 encoded)
    private static let tokenByteLength = 32

    // MARK: - Singleton

    static let shared = ShareService()
    private init() {}

    // MARK: - Token Generation

    /// Generate a cryptographically secure token
    private func generateToken() -> String {
        var bytes = [UInt8](repeating: 0, count: Self.tokenByteLength)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes).base64EncodedString()
            .replacingOccurrences(of: "+", with: "-")
            .replacingOccurrences(of: "/", with: "_")
            .replacingOccurrences(of: "=", with: "")
    }

    // MARK: - Share Creation

    /// Create a new share for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir to share
    ///   - context: Managed object context
    ///   - expirationInterval: How long until the share expires (default 48 hours)
    /// - Returns: The created ShareEntity
    func createShare(
        for souvenir: SouvenirEntity,
        in context: NSManagedObjectContext,
        expirationInterval: TimeInterval = defaultExpirationInterval
    ) -> ShareEntity {
        let share = ShareEntity(context: context)
        share.id = UUID()
        share.token = generateToken()
        share.createdAt = Date()
        share.expiresAt = Date().addingTimeInterval(expirationInterval)
        share.isRevoked = false
        share.souvenir = souvenir

        return share
    }

    // MARK: - URL Generation

    /// Generate a Universal Link URL for a share
    /// - Parameter share: The share entity
    /// - Returns: The shareable URL
    func shareURL(for share: ShareEntity) -> URL {
        var components = URLComponents(string: Self.baseURL)!
        components.path = "/s/\(share.token)"
        return components.url!
    }

    /// Generate a Universal Link URL with souvenir metadata for deep linking
    /// - Parameters:
    ///   - share: The share entity
    ///   - includeMetadata: Whether to include timestamp/location query params
    /// - Returns: The shareable URL with optional metadata
    ///
    /// Metadata is encoded as a single `m` parameter: base64(timestamp_plusCode)
    /// This obscures the raw values while remaining decodable.
    func shareURL(for share: ShareEntity, includeMetadata: Bool) -> URL {
        var components = URLComponents(string: Self.baseURL)!
        components.path = "/s/\(share.token)"

        if includeMetadata, let souvenir = share.souvenir {
            // Build metadata string: timestamp_plusCode
            var metadataParts: [String] = []

            if let timestamp = souvenir.latestPhotoTimestamp {
                metadataParts.append(String(Int(timestamp.timeIntervalSince1970)))
            }

            // Get plusCode from latest photo
            if let latestPhoto = souvenir.photosArray.first,
               let plusCode = latestPhoto.plusCode, !plusCode.isEmpty {
                metadataParts.append(plusCode)
            }

            if !metadataParts.isEmpty {
                let metadata = metadataParts.joined(separator: "_")
                // Base64 encode to obscure the values
                if let data = metadata.data(using: .utf8) {
                    let encoded = data.base64EncodedString()
                        .replacingOccurrences(of: "+", with: "-")
                        .replacingOccurrences(of: "/", with: "_")
                        .replacingOccurrences(of: "=", with: "")
                    components.queryItems = [URLQueryItem(name: "m", value: encoded)]
                }
            }
        }

        return components.url!
    }

    /// Decode metadata from a share URL
    /// - Parameter url: The incoming URL
    /// - Returns: Tuple of (timestamp, plusCode) if decodable
    func decodeMetadata(from url: URL) -> (timestamp: Date?, plusCode: String?)? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems,
              let mValue = queryItems.first(where: { $0.name == "m" })?.value else {
            return nil
        }

        // Decode base64
        var encoded = mValue
            .replacingOccurrences(of: "-", with: "+")
            .replacingOccurrences(of: "_", with: "/")
        // Add padding if needed
        while encoded.count % 4 != 0 {
            encoded += "="
        }

        guard let data = Data(base64Encoded: encoded),
              let decoded = String(data: data, encoding: .utf8) else {
            return nil
        }

        let parts = decoded.split(separator: "_", maxSplits: 1)
        var timestamp: Date?
        var plusCode: String?

        if let firstPart = parts.first, let epochSeconds = Int(firstPart) {
            timestamp = Date(timeIntervalSince1970: TimeInterval(epochSeconds))
        }

        if parts.count > 1 {
            plusCode = String(parts[1])
        }

        return (timestamp, plusCode)
    }

    // MARK: - Token Validation

    /// Validate a share token and return the associated souvenir
    /// - Parameters:
    ///   - token: The token to validate
    ///   - context: Managed object context
    /// - Returns: The souvenir if valid, nil otherwise
    func validateToken(_ token: String, in context: NSManagedObjectContext) -> SouvenirEntity? {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(
            format: "token == %@ AND isRevoked == NO AND expiresAt > %@",
            token,
            Date() as NSDate
        )
        request.fetchLimit = 1

        guard let share = try? context.fetch(request).first else {
            return nil
        }

        return share.souvenir
    }

    /// Parse a token from a Universal Link or custom scheme URL
    /// - Parameter url: The incoming URL (https://souvenir.kerry.ink/s/TOKEN or souvenir://s/TOKEN)
    /// - Returns: The token if present, nil otherwise
    func parseToken(from url: URL) -> String? {
        // Universal Link: https://souvenir.kerry.ink/s/TOKEN
        // pathComponents = ["/", "s", "TOKEN"]
        let pathComponents = url.pathComponents
        if pathComponents.count >= 2,
           pathComponents[pathComponents.count - 2] == "s" {
            return pathComponents.last
        }

        // Custom URL scheme: souvenir://s/TOKEN
        // host = "s", path = "/TOKEN"
        if url.scheme == "souvenir", url.host == "s" {
            let token = url.path.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
            return token.isEmpty ? nil : token
        }

        return nil
    }

    // MARK: - Share Management

    /// Fetch active shares for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir
    ///   - context: Managed object context
    /// - Returns: Array of active (non-expired, non-revoked) shares
    func activeShares(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) -> [ShareEntity] {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(
            format: "souvenir == %@ AND isRevoked == NO AND expiresAt > %@",
            souvenir,
            Date() as NSDate
        )
        request.sortDescriptors = [NSSortDescriptor(key: "createdAt", ascending: false)]

        return (try? context.fetch(request)) ?? []
    }

    /// Revoke all shares for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir
    ///   - context: Managed object context
    func revokeAllShares(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) {
        let shares = activeShares(for: souvenir, in: context)
        shares.forEach { $0.revoke() }
    }

    // MARK: - Share Text Generation

    /// Generate share text for SMS (non-user recipient)
    /// - Parameters:
    ///   - souvenir: The souvenir being shared
    ///   - share: The share entity with token
    /// - Returns: Formatted message text
    func smsShareText(for souvenir: SouvenirEntity, share: ShareEntity) -> String {
        var text = ""

        // Caption or contact name
        if let caption = souvenir.caption, !caption.isEmpty {
            text = caption
        } else if let contactName = souvenir.primaryContact?.displayName {
            text = "Check out my souvenir with \(contactName)!"
        } else {
            text = "Check out my souvenir!"
        }

        // Add view link
        let url = shareURL(for: share)
        text += "\n\n\(url.absoluteString)"

        // Add App Store invite
        text += "\n\nGet Souvenir: \(Self.appStoreURL)"

        return text
    }

    /// Generate share text for in-app sharing (user recipient)
    /// - Parameters:
    ///   - souvenir: The souvenir being shared
    ///   - share: The share entity with token
    /// - Returns: Formatted message text with precise metadata
    func inAppShareText(for souvenir: SouvenirEntity, share: ShareEntity) -> String {
        var text = ""

        // Caption or contact name
        if let caption = souvenir.caption, !caption.isEmpty {
            text = caption
        } else if let contactName = souvenir.primaryContact?.displayName {
            text = "Souvenir with \(contactName)"
        } else {
            text = "A Souvenir"
        }

        // Add deep link with metadata
        let url = shareURL(for: share, includeMetadata: true)
        text += "\n\n\(url.absoluteString)"

        return text
    }

    // MARK: - Share State

    /// Derive the current share state for a souvenir from its ShareEntity rows.
    /// - Parameters:
    ///   - souvenir: The souvenir to check.
    ///   - context: Managed object context.
    func shareState(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) -> ShareState {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(format: "souvenir == %@", souvenir)
        guard let shares = try? context.fetch(request), !shares.isEmpty else {
            return .localOnly
        }
        if shares.contains(where: { $0.status == ShareStatus.accepted && !$0.isRevoked }) {
            return .sharedActive
        }
        if shares.contains(where: { $0.status == ShareStatus.pending && !$0.isRevoked }) {
            return .pendingInvite
        }
        return .sharedRevoked
    }

    // MARK: - CloudKit Share Lifecycle

    /// Create a CKShare for a souvenir and save the owner's ShareEntity row.
    /// - Parameters:
    ///   - souvenir: The souvenir to share.
    ///   - container: The NSPersistentCloudKitContainer.
    ///   - context: Managed object context for saving ShareEntity.
    ///   - inviterUserId: Current user's CloudKit record name (from CKCurrentUserDefaultName or fetched identity).
    /// - Returns: The CKShare URL to send to the recipient.
    func createAndSaveShare(
        for souvenir: SouvenirEntity,
        container: NSPersistentCloudKitContainer,
        in context: NSManagedObjectContext,
        inviterUserId: String
    ) async throws -> URL {
        // Pre-compute values from non-Sendable souvenir before the @Sendable closure
        let souvenirTitle = souvenir.displayTitle
        let souvenirIDString = souvenir.id.uuidString
        let souvenirObjectID = souvenir.objectID

        let share: CKShare = try await withCheckedThrowingContinuation { continuation in
            container.share([souvenir], to: nil) { _, share, _, error in
                if let error = error {
                    continuation.resume(throwing: error)
                    return
                }
                guard let share else {
                    continuation.resume(throwing: ShareError.shareCreationFailed)
                    return
                }
                share[CKShare.SystemFieldKey.title] = souvenirTitle as CKRecordValue
                continuation.resume(returning: share)
            }
        }

        guard let shareURL = share.url else {
            throw ShareError.shareURLUnavailable
        }

        let shareRecordName = share.recordID.recordName
        try await context.perform {
            let shareEntity = ShareEntity(context: context)
            shareEntity.id = UUID()
            shareEntity.createdAt = Date()
            shareEntity.expiresAt = Date().addingTimeInterval(72 * 60 * 60)
            shareEntity.isRevoked = false
            shareEntity.token = shareRecordName
            shareEntity.status = ShareStatus.pending
            shareEntity.role = ShareRole.owner
            shareEntity.inviterUserId = inviterUserId
            shareEntity.cloudKitShareRecordName = shareRecordName
            shareEntity.cloudKitRootRecordName = souvenirIDString
            shareEntity.cloudKitShareURL = shareURL.absoluteString
            shareEntity.souvenir = context.object(with: souvenirObjectID) as? SouvenirEntity
            try context.save()
        }

        return shareURL
    }

    /// Revoke a share — marks the ShareEntity revoked locally.
    /// CloudKit participant removal is left to the system on next sync.
    /// - Parameters:
    ///   - shareEntity: The share to revoke.
    ///   - context: Managed object context.
    func revokeShare(
        _ shareEntity: ShareEntity,
        in context: NSManagedObjectContext
    ) async throws {
        let objectID = shareEntity.objectID
        try await context.perform {
            guard let share = context.object(with: objectID) as? ShareEntity else { return }
            share.isRevoked = true
            share.revokedAt = Date()
            share.status = ShareStatus.revoked
            try context.save()
        }
    }

    /// Accept a CloudKit share invitation and record the participation in Core Data.
    /// Call this from the UIApplicationDelegate share-acceptance callback.
    /// - Parameters:
    ///   - metadata: CKShare.Metadata received from the system.
    ///   - persistentStore: The NSPersistentStore to import the shared zone into.
    ///   - container: The NSPersistentCloudKitContainer.
    ///   - context: Managed object context.
    func acceptShareInvitation(
        metadata: CKShare.Metadata,
        into persistentStore: NSPersistentStore,
        container: NSPersistentCloudKitContainer,
        in context: NSManagedObjectContext
    ) async throws {
        try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<Void, Error>) in
            container.acceptShareInvitations(from: [metadata], into: persistentStore) { _, error in
                if let error = error {
                    continuation.resume(throwing: error)
                } else {
                    continuation.resume()
                }
            }
        }

        let shareRecordName = metadata.share.recordID.recordName
        let rootRecordName = metadata.hierarchicalRootRecordID?.recordName ?? metadata.share.recordID.recordName

        try await context.perform {
            let shareEntity = ShareEntity(context: context)
            shareEntity.id = UUID()
            shareEntity.createdAt = Date()
            shareEntity.expiresAt = Date().addingTimeInterval(72 * 60 * 60)
            shareEntity.isRevoked = false
            shareEntity.token = shareRecordName
            shareEntity.status = ShareStatus.accepted
            shareEntity.acceptedAt = Date()
            shareEntity.role = ShareRole.participant
            shareEntity.cloudKitShareRecordName = shareRecordName
            shareEntity.cloudKitRootRecordName = rootRecordName
            // souvenir will be linked by CloudKit sync after acceptance
            try context.save()
        }
    }
}

