import SwiftUI
import PhotosUI
import CoreLocation
import Combine

/// Service for picking photos and extracting metadata.
@MainActor
public final class PhotoPickerService: ObservableObject {
    @Published public var selectedPhoto: PhotoPickerItem?
    @Published public var isPresented = false

    /// Pick a photo using PhotosUI picker.
    public func presentPicker() {
        isPresented = true
    }

    /// Extract metadata from selected photo item.
    public func extractMetadata(from item: PhotosPickerItem) async -> PhotoMetadata? {
        // Load the asset identifier
        guard let assetID = item.itemIdentifier else { return nil }

        // TODO: Phase 4 - Extract location, timestamp, timezone from PHAsset
        // For now, return basic metadata
        return PhotoMetadata(
            assetLocalId: assetID,
            timestamp: Date(),
            timezoneID: TimeZone.current.identifier,
            location: nil
        )
    }
}

/// Metadata extracted from a photo.
public struct PhotoMetadata: Equatable {
    public let assetLocalId: String
    public let timestamp: Date
    public let timezoneID: String
    public let location: (latitude: Double, longitude: Double)?

    // New: Support for camera-captured photos before they're saved to library
    public var capturedImage: UIImage?
    public var geocodedAddress: GeocodedAddress?  // Full address object
    public var plusCode: String?

    public init(
        assetLocalId: String,
        timestamp: Date,
        timezoneID: String,
        location: (latitude: Double, longitude: Double)?,
        capturedImage: UIImage? = nil,
        geocodedAddress: GeocodedAddress? = nil,
        plusCode: String? = nil
    ) {
        self.assetLocalId = assetLocalId
        self.timestamp = timestamp
        self.timezoneID = timezoneID
        self.location = location
        self.capturedImage = capturedImage
        self.geocodedAddress = geocodedAddress
        self.plusCode = plusCode
    }

    public static func == (lhs: PhotoMetadata, rhs: PhotoMetadata) -> Bool {
        return lhs.assetLocalId == rhs.assetLocalId &&
               lhs.timestamp == rhs.timestamp &&
               lhs.timezoneID == rhs.timezoneID &&
               lhs.location?.latitude == rhs.location?.latitude &&
               lhs.location?.longitude == rhs.location?.longitude &&
               lhs.geocodedAddress == rhs.geocodedAddress &&
               lhs.plusCode == rhs.plusCode
        // Note: UIImage is not Equatable, so we skip it in equality check
    }
}

/// Wrapper for PhotosUI picker item.
public struct PhotoPickerItem: Identifiable {
    public let id = UUID()
    public let item: PhotosPickerItem
    public let metadata: PhotoMetadata?
}

