//
//  ViewsAdminDualInviteView.swift
//  souvenir
//
//  Created by Kerrbear on 23.02.2026.
//

#if DEBUG
import UIKit
import SwiftUI
import Contacts
import ContactsUI
import PhotosUI
import CoreData
import MessageUI

// MARK: - Main View

struct AdminDualInviteView: View {
    @State private var contactA: CNContact?
    @State private var contactB: CNContact?
    @State private var pickerTarget: PickerTarget?
    @State private var selectedPhoto: PhotosPickerItem?
    @State private var shareURL: URL?
    @State private var isGenerating = false
    @State private var errorMessage: String?
    @State private var messageRecipient: String?
    @State private var showMessageCompose = false

    @Environment(\.managedObjectContext) private var viewContext

    let container: NSPersistentContainer

    var body: some View {
        Form {
            Section("Contacts") {
                HStack {
                    Text("Person 1")
                    Spacer()
                    if let contactA = contactA {
                        Text(contactA.givenName)
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    } else {
                        Text("Tap to select")
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    }
                }
                .onTapGesture {
                    pickerTarget = .personA
                }

                HStack {
                    Text("Person 2")
                    Spacer()
                    if let contactB = contactB {
                        Text(contactB.givenName)
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    } else {
                        Text("Tap to select")
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    }
                }
                .onTapGesture {
                    pickerTarget = .personB
                }
            }

            Section("Photo") {
                PhotosPicker(selection: $selectedPhoto, matching: .images) {
                    if let selectedPhoto = selectedPhoto {
                        HStack {
                            Image(systemName: "photo.fill")
                                .svnrSymbolPalette()
                            Text("Photo selected")
                            Spacer()
                            Image(systemName: "checkmark.circle.fill")
                                .foregroundStyle(Color.green)
                        }
                    } else {
                        HStack {
                            Image(systemName: "photo")
                                .svnrSymbolPalette()
                            Text("Tap to pick photo")
                        }
                    }
                }
            }

            if contactA != nil && contactB != nil && selectedPhoto != nil {
                Section("Generate") {
                    Button {
                        generateInvite()
                    } label: {
                        HStack {
                            Image(systemName: "sparkles")
                                .svnrSymbolPalette()
                            Text("Create Invite")

                            if isGenerating {
                                Spacer()
                                ProgressView()
                                    .controlSize(.small)
                            }
                        }
                    }
                    .disabled(isGenerating)
                }
            }

            if let shareURL = shareURL {
                Section("Invite Link") {
                    VStack(alignment: .leading, spacing: 12) {
                        HStack {
                            Text(shareURL.absoluteString.prefix(60) + "...")
                                .font(.footnote)
                                .fontWeight(.medium)
                                .lineLimit(1)
                            Spacer()
                            Button {
                                UIPasteboard.general.string = shareURL.absoluteString
                            } label: {
                                Image(systemName: "doc.on.doc")
                                    .svnrSymbolPalette()
                            }
                        }

                        if let contactA = contactA {
                            Button {
                                messageRecipient = contactA.phoneNumbers.first?.value.stringValue ?? ""
                                showMessageCompose = true
                            } label: {
                                HStack {
                                    Image(systemName: "message.fill")
                                        .svnrSymbolPalette()
                                    Text("Send to \(contactA.givenName)")
                                }
                            }
                        }

                        if let contactB = contactB {
                            Button {
                                messageRecipient = contactB.phoneNumbers.first?.value.stringValue ?? ""
                                showMessageCompose = true
                            } label: {
                                HStack {
                                    Image(systemName: "message.fill")
                                        .svnrSymbolPalette()
                                    Text("Send to \(contactB.givenName)")
                                }
                            }
                        }
                    }
                }
            }

            if let errorMessage = errorMessage {
                Section {
                    Text(errorMessage)
                        .font(.caption)
                        .foregroundColor(.red)
                }
            }
        }
        .sheet(item: $pickerTarget) { target in
            CNContactPickerRepresentable(selectedContact: target == .personA ? $contactA : $contactB)
        }
        .sheet(isPresented: $showMessageCompose) {
            if let recipient = messageRecipient, let url = shareURL {
                MessageComposeRepresentable(recipient: recipient, body: url.absoluteString)
            }
        }
    }

    private func generateInvite() {
        guard let contactA = contactA, let selectedPhoto = selectedPhoto else { return }

        isGenerating = true
        errorMessage = nil

        Task {
            do {
                // Step 1: Import Contact A into Core Data
                let contactSearchService = ContactSearchService(persistenceController: .shared)
                let contactEntityA = try await contactSearchService.importSystemContact(contactA)

                // Step 2: Extract photo metadata
                let photoPickerService = PhotoPickerService()
                guard let photoMetadata = await photoPickerService.extractMetadata(from: selectedPhoto) else {
                    throw NSError(domain: "PhotoMetadata", code: -1, userInfo: [NSLocalizedDescriptionKey: "Failed to extract photo metadata"])
                }

                // Step 3: Create souvenir (this will fail if contact already has one)
                let souvenirCaptureService = SouvenirCaptureService(persistenceController: .shared)
                let souvenirID = try await souvenirCaptureService.createSouvenir(
                    photo: photoMetadata,
                    contact: contactEntityA,
                    caption: nil
                )

                // Step 4: Fetch the souvenir from viewContext
                let souvenir = try viewContext.fetch(
                    NSFetchRequest<SouvenirEntity>(entityName: "SouvenirEntity")
                        .then { $0.predicate = NSPredicate(format: "id == %@", souvenirID as CVarArg) }
                ).first

                guard let souvenir = souvenir else {
                    throw NSError(domain: "Souvenir", code: -1, userInfo: [NSLocalizedDescriptionKey: "Failed to fetch created souvenir"])
                }

                // Step 5: Create share and get URL
                let shareService = ShareService.shared
                let ckContainer = container as? NSPersistentCloudKitContainer ?? NSPersistentCloudKitContainer(name: "SouvenirModel")
                let inviterUserID = "debug-admin"

                let url = try await shareService.createAndSaveShare(
                    for: souvenir,
                    container: ckContainer,
                    in: viewContext,
                    inviterUserId: inviterUserID
                )

                await MainActor.run {
                    shareURL = url
                    isGenerating = false
                    print("✅ Share created: \(url.absoluteString)")
                }
            } catch {
                await MainActor.run {
                    if let validationError = error as? ValidationError {
                        errorMessage = "Validation error: \(validationError.localizedDescription)"
                    } else if let souvenirError = error as? SouvenirCaptureError {
                        switch souvenirError {
                        case .contactNotFound:
                            errorMessage = "Contact not found in database"
                        case .photoLoadFailed:
                            errorMessage = "Failed to load photo metadata"
                        case .saveFailed(let err):
                            errorMessage = "Failed to save souvenir: \(err.localizedDescription)"
                        case .validationFailed(let validationErr):
                            if validationErr.localizedDescription.contains("already has") {
                                errorMessage = "Contact already has a souvenir"
                            } else {
                                errorMessage = validationErr.localizedDescription
                            }
                        }
                    } else if let shareError = error as? ShareError {
                        errorMessage = shareError.localizedDescription
                    } else {
                        errorMessage = "Error: \(error.localizedDescription)"
                    }
                    isGenerating = false
                    print("❌ Share creation failed: \(error)")
                }
            }
        }
    }
}

