import Foundation
import CoreData
import Photos

// MARK: - Validation Error Types

public enum ValidationError: LocalizedError, Equatable {
    case invalidPhoneFormat(String)
    case invalidEmailFormat(String)
    case invalidCoordinates(latitude: Double, longitude: Double)
    case missingRequiredField(String)
    case souvenirRequiresAtLeastOnePhoto
    case contactRequiresPhoneOrEmail
    case contactRequiresGivenName
    case duplicatePhotoInSouvenir
    case invalidPhotoContactRelationship
    case invalidGeographicRange(field: String, value: Double, min: Double, max: Double)
    case custom(String)

    public var errorDescription: String? {
        switch self {
        case .invalidPhoneFormat(let phone):
            return "Phone number '" + phone + "' is not in valid E.164 format. Expected format: +[country code][number]"
        case .invalidEmailFormat(let email):
            return "Email address '" + email + "' is not valid"
        case .invalidCoordinates(let lat, let lon):
            return "Invalid coordinates: (" + String(lat) + ", " + String(lon) + "). Latitude must be between -90 and 90, longitude between -180 and 180"
        case .missingRequiredField(let field):
            return "Missing required field: " + field
        case .souvenirRequiresAtLeastOnePhoto:
            return "Souvenir must contain at least one photo"
        case .contactRequiresPhoneOrEmail:
            return "Contact must have either a phone number or email address"
        case .contactRequiresGivenName:
            return "Contact must have at least a given name"
        case .duplicatePhotoInSouvenir:
            return "Cannot add the same photo multiple times to a souvenir"
        case .invalidPhotoContactRelationship:
            return "Photo and contact relationship is invalid"
        case .invalidGeographicRange(let field, let value, let min, let max):
            return "Invalid " + field + " value: " + String(value) + ". Must be between " + String(min) + " and " + String(max)
        case .custom(let message):
            return message
        }
    }

    public var recoverySuggestion: String? {
        switch self {
        case .invalidPhoneFormat:
            return "Please enter phone number in international format (e.g., +12175551234)"
        case .invalidEmailFormat:
            return "Please enter a valid email address (e.g., user@example.com)"
        case .invalidCoordinates:
            return "Please ensure coordinates are within valid geographic ranges"
        case .contactRequiresPhoneOrEmail:
            return "Please provide either a phone number or email address for this contact"
        case .contactRequiresGivenName:
            return "Please provide at least a given name for this contact"
        case .souvenirRequiresAtLeastOnePhoto:
            return "Please add at least one photo to create a souvenir"
        default:
            return nil
        }
    }
}

// MARK: - Validation Service

/// Service for validating data according to Phase 14 requirements
public struct ValidationService {

    // MARK: - Phone Validation

    /// Validate phone number format (E.164)
    /// - Parameter phone: Phone number to validate
    /// - Returns: True if valid E.164 format, false otherwise
    public static func validatePhoneFormat(_ phone: String?) -> Bool {
        guard let phone = phone, !phone.isEmpty else { return false }

        // E.164 format: + followed by country code and number (digits only)
        let pattern = #"^\+\d{11,15}$"#
        let regex = try? NSRegularExpression(pattern: pattern)
        let range = NSRange(location: 0, length: phone.utf16.count)

        return regex?.firstMatch(in: phone, options: [], range: range) != nil
    }

    /// Validate phone number format and throw detailed error if invalid
    /// - Parameter phone: Phone number to validate
    /// - Throws: ValidationError.invalidPhoneFormat if validation fails
    public static func validatePhoneFormatOrThrow(_ phone: String?) throws {
        guard let phone = phone, !phone.isEmpty else {
            throw ValidationError.missingRequiredField("phone number")
        }

        if !validatePhoneFormat(phone) {
            throw ValidationError.invalidPhoneFormat(phone)
        }
    }

    // MARK: - Email Validation

    /// Validate email format
    /// - Parameter email: Email address to validate
    /// - Returns: True if valid email format, false otherwise
    public static func validateEmailFormat(_ email: String?) -> Bool {
        guard let email = email, !email.isEmpty else { return false }

        // Basic email format validation
        let pattern = #"^[A-Za-z0-9._%+\-]+@([A-Za-z0-9\-]+\.)+[A-Za-z]{2,}$"#
        let regex = try? NSRegularExpression(pattern: pattern)
        let range = NSRange(location: 0, length: email.utf16.count)

        return regex?.firstMatch(in: email, options: [], range: range) != nil
    }

    /// Validate email format and throw detailed error if invalid
    /// - Parameter email: Email address to validate
    /// - Throws: ValidationError.invalidEmailFormat if validation fails
    public static func validateEmailFormatOrThrow(_ email: String?) throws {
        guard let email = email, !email.isEmpty else {
            throw ValidationError.missingRequiredField("email")
        }

        if !validateEmailFormat(email) {
            throw ValidationError.invalidEmailFormat(email)
        }
    }

    // MARK: - Geographic Coordinate Validation

    /// Validate latitude is within valid range (-90 to 90)
    /// - Parameter latitude: Latitude value to validate
    /// - Throws: ValidationError.invalidGeographicRange if validation fails
    public static func validateLatitude(_ latitude: Double) throws {
        if latitude < -90.0 || latitude > 90.0 {
            throw ValidationError.invalidGeographicRange(field: "latitude", value: latitude, min: -90.0, max: 90.0)
        }
    }

    /// Validate longitude is within valid range (-180 to 180)
    /// - Parameter longitude: Longitude value to validate
    /// - Throws: ValidationError.invalidGeographicRange if validation fails
    public static func validateLongitude(_ longitude: Double) throws {
        if longitude < -180.0 || longitude > 180.0 {
            throw ValidationError.invalidGeographicRange(field: "longitude", value: longitude, min: -180.0, max: 180.0)
        }
    }

    /// Validate coordinates (latitude and longitude)
    /// - Parameters:
    ///   - latitude: Latitude value
    ///   - longitude: Longitude value
    /// - Throws: ValidationError if validation fails
    public static func validateCoordinates(latitude: Double, longitude: Double) throws {
        try validateLatitude(latitude)
        try validateLongitude(longitude)
    }

    // MARK: - Contact Validation

    /// Validate contact has required fields (Phase 14: Rule 9, Rule 11)
    /// - Parameters:
    ///   - givenName: Contact's given name
    ///   - familyName: Contact's family name (optional)
    ///   - phone: Contact's phone number (optional)
    ///   - email: Contact's email address (optional)
    /// - Throws: ValidationError if validation fails
    public static func validateContactRequirements(
        givenName: String?,
        familyName: String?,
        phone: String?,
        email: String?,
        allowMissingContactMethods: Bool = false,
        allowMissingGivenName: Bool = false
    ) throws {
        var validationErrors: [ValidationError] = []

        // Rule 11: At least given name required
        let hasGivenName = givenName != nil && !(givenName?.isEmpty ?? true)

        if !allowMissingGivenName && !hasGivenName {
            validationErrors.append(.contactRequiresGivenName)
        }

        // Rule 9: Phone OR email required
        let hasPhone = phone != nil && !(phone?.isEmpty ?? true)
        let hasEmail = email != nil && !(email?.isEmpty ?? true)

        if !allowMissingContactMethods && !hasPhone && !hasEmail {
            validationErrors.append(.contactRequiresPhoneOrEmail)
        }

        // If phone provided, validate format
        if let phone = phone, !phone.isEmpty {
            do {
                try validatePhoneFormatOrThrow(phone)
            } catch let error as ValidationError {
                validationErrors.append(error)
            }
        }

        // If email provided, validate format
        if let email = email, !email.isEmpty {
            do {
                try validateEmailFormatOrThrow(email)
            } catch let error as ValidationError {
                validationErrors.append(error)
            }
        }

        // If we have multiple errors, throw a combined error message
        if validationErrors.count > 1 {
            let errorDescriptions = validationErrors.compactMap { $0.errorDescription }
            let combinedMessage = errorDescriptions.joined(separator: "; ")
            throw ValidationError.custom("Multiple validation errors occurred: \(combinedMessage)")
        } else if let firstError = validationErrors.first {
            throw firstError
        }
    }

    /// Validate contact entity
    /// - Parameter contact: ContactEntity to validate
    /// - Throws: ValidationError if validation fails
    public static func validateContact(_ contact: ContactEntity) throws {
        // Skip strict validation for incremental onboarding flows, but enforce uniqueness.
        try enforceContactUniqueness(contact)
    }

    // MARK: - Souvenir Validation

    /// Validate souvenir has required fields (Phase 14: Rule 6)
    /// - Parameter souvenir: SouvenirEntity to validate
    /// - Throws: ValidationError if validation fails
    public static func validateSouvenir(_ souvenir: SouvenirEntity) throws {
        if souvenir.photosArray.isEmpty {
            throw ValidationError.souvenirRequiresAtLeastOnePhoto
        }
        if souvenir.primaryContact == nil {
            throw ValidationError.missingRequiredField("primary contact")
        }
    }

    /// Validate share entity
    /// - Parameter share: ShareEntity to validate
    /// - Throws: ValidationError if validation fails
    public static func validateShare(_ share: ShareEntity) throws {
        try enforceShareUniqueness(share)
    }

    // MARK: - Photo Validation

    /// Validate photo has required fields
    /// - Parameter photo: PhotoEntity to validate
    /// - Throws: ValidationError if validation fails
    public static func validatePhoto(_ photo: PhotoEntity) throws {
        let context = photo.managedObjectContext
        if context?.userInfo["allowEmptyAssetLocalId"] as? Bool == true {
            return
        }
        // Photo must have an assetLocalId
        if photo.assetLocalId == nil || photo.assetLocalId?.isEmpty == true {
            throw ValidationError.missingRequiredField("assetLocalId")
        }
        let assetLocalId = photo.assetLocalId!

        try enforcePhotoUniqueness(photo, assetLocalId: assetLocalId)
        _ = validatePhotoAssetQuality(assetLocalId: assetLocalId)

        // If coordinates provided, validate them
        if let latitude = photo.latitude?.doubleValue,
           let longitude = photo.longitude?.doubleValue {
            try validateCoordinates(latitude: latitude, longitude: longitude)
        }
    }

    /// Validate photo asset size and resolution (Phase 14.1)
    /// - Parameter assetLocalId: Photos asset identifier
    /// - Returns: Warning messages (non-blocking)
    /// - Note: Skips local/seed assets and unauthorized Photos access to avoid prompts during onboarding.
    public static func validatePhotoAssetQuality(assetLocalId: String) -> [String] {
        if assetLocalId.hasPrefix("local://") || assetLocalId.hasPrefix("seed://") {
            return []
        }
        let status = PHPhotoLibrary.authorizationStatus(for: .readWrite)
        guard status == .authorized || status == .limited else {
            return []
        }
        let fetchResult = PHAsset.fetchAssets(withLocalIdentifiers: [assetLocalId], options: nil)
        guard let asset = fetchResult.firstObject else { return [] }

        var warnings: [String] = []

        // Rule 14: Resolution > 24x24 pixels
        if asset.pixelWidth <= 24 || asset.pixelHeight <= 24 {
            warnings.append("Photo resolution is very low (\(asset.pixelWidth)x\(asset.pixelHeight))")
        }

        // Rule 13: File size <= 1 GB (best effort)
        if let resource = PHAssetResource.assetResources(for: asset).first,
           let fileSize = resource.value(forKey: "fileSize") as? Int64 {
            let maxSize = Int64(1_073_741_824)
            if fileSize > maxSize {
                warnings.append("Photo file size exceeds 1 GB")
            }
        }

        if !warnings.isEmpty {
            print("⚠️ Photo quality warnings: \(warnings.joined(separator: " | "))")
        }

        return warnings
    }

    // MARK: - Relationship Validation

    /// Validate photo-contact relationship (Phase 14: Rule 15)
    /// - Parameters:
    ///   - photo: PhotoEntity
    ///   - contact: ContactEntity
    ///   - souvenir: SouvenirEntity (optional)
    /// - Throws: ValidationError if validation fails
    public static func validatePhotoContactRelationship(
        photo: PhotoEntity,
        contact: ContactEntity,
        souvenir: SouvenirEntity? = nil
    ) throws {
        // Check if photo already has this contact
        _ = photo.contactsArray.contains { $0.id == contact.id }

        // If souvenir provided, check if contact is the primary contact
        if let souvenir = souvenir {
            if souvenir.primaryContact?.id != contact.id {
                throw ValidationError.invalidPhotoContactRelationship
            }
        }
    }

    /// Validate bidirectional relationship consistency (Phase 14.1)
    public static func validateRelationshipIntegrity(
        photo: PhotoEntity,
        contact: ContactEntity,
        souvenir: SouvenirEntity
    ) throws {
        let contactHasPhoto = contact.photosArray.contains { $0.id == photo.id }
        let photoHasContact = photo.contactsArray.contains { $0.id == contact.id }
        if contactHasPhoto != photoHasContact {
            throw ValidationError.invalidPhotoContactRelationship
        }

        let souvenirHasPhoto = souvenir.photosArray.contains { $0.id == photo.id }
        let photoHasSouvenir = photo.souvenirsArray.contains { $0.id == souvenir.id }
        if souvenirHasPhoto != photoHasSouvenir {
            throw ValidationError.invalidPhotoContactRelationship
        }
    }

    /// Check if photo already exists in souvenir (Phase 14: Rule 15)
    /// - Parameters:
    ///   - photo: PhotoEntity
    ///   - souvenir: SouvenirEntity
    /// - Returns: True if photo already exists in souvenir, false otherwise
    public static func checkDuplicatePhotoInSouvenir(
        photo: PhotoEntity,
        souvenir: SouvenirEntity
    ) -> Bool {
        return souvenir.photosArray.contains { $0.id == photo.id }
    }

    // MARK: - Phase 15.1 Warnings (Non-blocking)

    /// Non-blocking sharing warnings for Phase 15.1
    public static func shareWarnings(for souvenir: SouvenirEntity) -> [String] {
        var warnings: [String] = []

        guard let contact = souvenir.primaryContact else {
            warnings.append("Sharing without a primary contact may reduce context.")
            return warnings
        }

        let hasPhone = !(contact.phoneE164 ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let hasEmail = !(contact.email ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty

        if !hasPhone && !hasEmail {
            warnings.append("This contact has no phone or email. Sharing may be less useful.")
        }

        return warnings
    }

    /// Non-blocking relationship integrity warnings for Phase 15.1
    public static func relationshipIntegrityWarnings(for souvenir: SouvenirEntity) -> [String] {
        var warnings: [String] = []

        if souvenir.primaryContact == nil {
            warnings.append("Souvenir is missing a primary contact.")
        } else if souvenir.primaryContact?.primarySouvenir?.id != souvenir.id {
            warnings.append("Primary contact does not point back to this souvenir.")
        }

        if souvenir.photosArray.isEmpty {
            warnings.append("Souvenir has no photos.")
        }

        return warnings
    }

    // MARK: - Uniqueness Enforcement (CloudKit Safe)

    private static func hasDuplicate(
        entityName: String,
        predicate: NSPredicate,
        excluding objectID: NSManagedObjectID,
        in context: NSManagedObjectContext
    ) throws -> Bool {
        let request = NSFetchRequest<NSFetchRequestResult>(entityName: entityName)
        request.fetchLimit = 1
        request.predicate = NSCompoundPredicate(andPredicateWithSubpredicates: [
            predicate,
            NSPredicate(format: "self != %@", objectID)
        ])
        return try context.count(for: request) > 0
    }

    private static func enforceContactUniqueness(_ contact: ContactEntity) throws {
        guard let context = contact.managedObjectContext else { return }

        let allowExternalId = context.userInfo["allowDuplicateContactExternalIdentifier"] as? Bool == true
        if !allowExternalId, let externalId = contact.externalIdentifier, !externalId.isEmpty {
            let predicate = NSPredicate(format: "externalIdentifier == %@", externalId)
            if try hasDuplicate(entityName: "ContactEntity", predicate: predicate, excluding: contact.objectID, in: context) {
                throw ValidationError.custom("Duplicate contact externalIdentifier: \(externalId)")
            }
        }

        let allowPhone = context.userInfo["allowDuplicateContactPhoneE164"] as? Bool == true
        if !allowPhone, let phone = contact.phoneE164, !phone.isEmpty {
            let predicate = NSPredicate(format: "phoneE164 == %@", phone)
            if try hasDuplicate(entityName: "ContactEntity", predicate: predicate, excluding: contact.objectID, in: context) {
                throw ValidationError.custom("Duplicate contact phoneE164: \(phone)")
            }
        }
    }

    private static func enforcePhotoUniqueness(_ photo: PhotoEntity, assetLocalId: String) throws {
        guard let context = photo.managedObjectContext else { return }
        let allowDuplicate = context.userInfo["allowDuplicatePhotoAssetLocalId"] as? Bool == true
        if allowDuplicate { return }
        let predicate = NSPredicate(format: "assetLocalId == %@", assetLocalId)
        if try hasDuplicate(entityName: "PhotoEntity", predicate: predicate, excluding: photo.objectID, in: context) {
            throw ValidationError.custom("Duplicate photo assetLocalId: \(assetLocalId)")
        }
    }

    private static func enforceShareUniqueness(_ share: ShareEntity) throws {
        guard let context = share.managedObjectContext else { return }
        let allowDuplicate = context.userInfo["allowDuplicateShareToken"] as? Bool == true
        if allowDuplicate { return }
        let token = share.token
        if token.isEmpty { return }
        let predicate = NSPredicate(format: "token == %@", token)
        if try hasDuplicate(entityName: "ShareEntity", predicate: predicate, excluding: share.objectID, in: context) {
            throw ValidationError.custom("Duplicate share token: \(token)")
        }
    }

    // MARK: - Context Utilities

    /// Allow saving PhotoEntity without an assetLocalId for specific flows (onboarding, previews, seeding)
    /// Set this on the context before attempting to save.
    /// - Parameter context: The NSManagedObjectContext to configure
    public static func allowEmptyPhotoAssetLocalId(on context: NSManagedObjectContext) {
        context.userInfo["allowEmptyAssetLocalId"] = true
    }

    /// Allow duplicate assetLocalId for special workflows (seeding/import).
    public static func allowDuplicatePhotoAssetLocalId(on context: NSManagedObjectContext) {
        context.userInfo["allowDuplicatePhotoAssetLocalId"] = true
    }

    /// Allow duplicate contact external identifiers or phone numbers (import/merge workflows).
    public static func allowDuplicateContactIdentifiers(on context: NSManagedObjectContext) {
        context.userInfo["allowDuplicateContactExternalIdentifier"] = true
        context.userInfo["allowDuplicateContactPhoneE164"] = true
    }

    /// Allow duplicate share tokens (testing only).
    public static func allowDuplicateShareTokens(on context: NSManagedObjectContext) {
        context.userInfo["allowDuplicateShareToken"] = true
    }
}

