/// Search both local contacts AND system contacts, returning unified results.
/// System contacts that are already imported are filtered out from system results.
/// Optionally filters out contacts that already have souvenirs.
public func searchAllContacts(query: String, includeSystem: Bool = true, excludeWithSouvenirs: Bool = false) async throws -> [ContactSearchResult] {
    var results: [ContactSearchResult] = []

    // 1. Search local Core Data contacts
    let localContacts = try await searchContacts(query: query)
    var filteredLocalContacts = localContacts

    // Filter out contacts that already have souvenirs if requested
    if excludeWithSouvenirs {
        filteredLocalContacts = localContacts.filter { $0.primarySouvenir == nil }
    }

    results.append(contentsOf: filteredLocalContacts.map { .local($0) })

    // 2. Search system contacts if permission granted and requested
    if includeSystem {
        let systemService = ContactsSystemService()
        if systemService.authorizationStatus() == .authorized {
            let systemContacts = try await systemService.searchContacts(query: query)

            // Filter out contacts already in our local database (by externalIdentifier)
            // and optionally those that already have souvenirs
            let systemResults = systemContacts
                .filter { cnContact in
                    let isNotImported = !localContacts.contains(where: { $0.externalIdentifier == cnContact.identifier })
                    if !excludeWithSouvenirs { return isNotImported }

                    // If already imported locally, check if it has a souvenir
                    if let importedContact = localContacts.first(where: { $0.externalIdentifier == cnContact.identifier }) {
                        return importedContact.primarySouvenir == nil
                    }
                    return isNotImported
                }
                .map { ContactSearchResult.system($0) }

            results.append(contentsOf: systemResults)
        }
    }

    return results
}

