import Foundation
import CoreData

struct CreateSouvenirTool: AgentTool {
    let id = "create_souvenir"
    let summary = "Create a new souvenir from a contact id and photo asset id."
    let inputSchema = [
        "contact_id": "Required. UUID string for the contact.",
        "asset_local_id": "Required. Photo asset local identifier.",
        "caption": "Optional. Caption for the souvenir."
    ]

    func run(_ input: AgentToolInput) async throws -> AgentActionResult {
        guard let contactIdRaw = input["contact_id"],
              let contactId = UUID(uuidString: contactIdRaw) else {
            return .failure("Invalid or missing contact_id.")
        }
        guard let assetLocalId = input["asset_local_id"], !assetLocalId.isEmpty else {
            return .failure("Missing asset_local_id.")
        }

        let context = PersistenceController.shared.container.viewContext
        let contact: ContactEntity? = await context.perform {
            let request: NSFetchRequest<ContactEntity> = ContactEntity.fetchRequest()
            request.fetchLimit = 1
            request.predicate = NSPredicate(format: "id == %@", contactId as CVarArg)
            return try? context.fetch(request).first
        }

        guard let contact else {
            return .failure("Contact not found.")
        }

        let metadata = PhotoMetadata(
            assetLocalId: assetLocalId,
            timestamp: Date(),
            timezoneID: TimeZone.current.identifier,
            location: nil
        )

        do {
            let captureService = SouvenirCaptureService(persistenceController: PersistenceController.shared)
            let souvenirId = try await captureService.createSouvenir(
                photo: metadata,
                contact: contact,
                caption: input["caption"]
            )
            await MainActor.run {
                AgentRuntimeState.shared.recordAction("tool:create_souvenir souvenir_id=\(souvenirId.uuidString)")
            }
            return .success("Souvenir created.", data: ["souvenir_id": souvenirId.uuidString])
        } catch {
            return .failure("Failed to create souvenir: \(error.localizedDescription)")
        }
    }
}

