    24→        return photosArray.first?.timestamp
    25→    }
    26→
    27→    /// Compute latest photo location (lat, lon) from most recent photo.
    28→    public func computeLatestPhotoLocation() -> (latitude: Double, longitude: Double)? {
    29→        guard let latest = photosArray.first,
    30→              let lat = latest.latitude?.doubleValue,
    31→              let lon = latest.longitude?.doubleValue else {
    32→            return nil
    33→        }
    34→        return (lat, lon)
    35→    }
    36→
    37→    /// Update derived fields from photos.
    38→    /// Phase 6: Now properly sets lastLatitude/lastLongitude and manages favoritePhoto.
    39→    public func recomputeDerivedFields() {
    40→        invalidatePhotosCache() // Clear cached photosArray
    41→        updatedAt = Date()
    42→
    43→        // Get the latest photo (most recent timestamp)
    44→        guard let latestPhoto = photosArray.first else {
    45→            // No photos - clear location data
    46→            lastLatitude = nil
    47→            lastLongitude = nil
    48→            favoritePhoto = nil
    49→            return
    50→        }
    51→
    52→        // Update lastLatitude and lastLongitude from latest photo
    53→        if let lat = latestPhoto.latitude?.doubleValue,
    54→           let lon = latestPhoto.longitude?.doubleValue {
    55→            lastLatitude = NSNumber(value: lat)
    56→            lastLongitude = NSNumber(value: lon)
    57→        } else {
    58→            lastLatitude = nil
    59→            lastLongitude = nil
    60→        }
    61→
    62→        if (meetPlace?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true),
    63→           let locationString = latestPhoto.locationString,
    64→           !locationString.isEmpty {
    65→            meetPlace = locationString
    66→        }
    67→
    68→        if meetTime == nil {
    69→            meetTime = latestPhoto.timestamp ?? createdAt
    70→        }
    71→
    72→        // If no favorite photo is set, make the latest photo the favorite
    73→        if favoritePhoto == nil {
    74→            favoritePhoto = latestPhoto
    75→        }
    76→    }
