    90→            lastLongitude = NSNumber(value: lon)
    91→        } else {
    92→            lastLatitude = nil
    93→            lastLongitude = nil
    94→        }
    95→
    96→        updatedAt = Date()
    97→    }
    98→
    99→    /// Deselect current favorite photo and revert to latest photo.
