     2→//  ViewsContactIslandState.swift
     3→//  souvenir
     4→//
     5→//  ContactIsland state machine for Find My-style floating drawer
     6→//
     7→
     8→import SwiftUI
     9→
    10→/// ContactIsland drawer states with springy transitions
    11→enum ContactIslandState: Equatable, CaseIterable, Hashable {
    12→    /// Floating capsule: name, location, date
    13→    case compact
    14→    /// Full sheet: + email, birthday, trophy
    15→    case fullSheet
    16→
    17→    /// Height for each state
    18→    var height: CGFloat {
    19→        switch self {
    20→        case .compact: return DesignTokens.ContactIsland.compactHeight
    21→        case .fullSheet: return DesignTokens.ContactIsland.fullSheetHeight
    22→        }
    23→    }
    24→
    25→    /// Whether the island is floating (compact) or attached to bottom
    26→    var isFloating: Bool {
    27→        self == .compact
    28→    }
    29→
    30→    /// Corner radius based on state
    31→    var cornerRadius: CGFloat {
    32→        switch self {
    33→        case .compact: return DesignTokens.ContactIsland.compactCornerRadius
    34→        case .fullSheet: return DesignTokens.ContactIsland.attachedCornerRadius
    35→        }
    36→    }
    37→
    38→    /// Next state when dragging up
    39→    var nextUp: ContactIslandState? {
    40→        switch self {
    41→        case .compact: return .fullSheet
    42→        case .fullSheet: return nil
    43→        }
    44→    }
    45→
    46→    /// Next state when dragging down
    47→    var nextDown: ContactIslandState? {
    48→        switch self {
    49→        case .compact: return nil
    50→        case .fullSheet: return .compact
    51→        }
    52→    }
    53→
    54→    /// Whether horizontal swipe navigation is allowed
    55→    var allowsHorizontalSwipe: Bool {
    56→        self == .compact
    57→    }
    58→
    59→    /// Presentation detent set for sheet-backed islands.
    60→    static func detents(
    61→        compactDetent: PresentationDetent,
    62→        fullSheetDetent: PresentationDetent = .large,
    63→        allowFullSheet: Bool = true
    64→    ) -> Set<PresentationDetent> {
    65→        allowFullSheet ? [compactDetent, fullSheetDetent] : [compactDetent]
    66→    }
    67→
    68→    /// Map state to presentation detent.
    69→    static func detent(
    70→        for state: ContactIslandState,
    71→        compactDetent: PresentationDetent,
    72→        fullSheetDetent: PresentationDetent = .large
    73→    ) -> PresentationDetent {
    74→        switch state {
    75→        case .compact:
    76→            return compactDetent
    77→        case .fullSheet:
    78→            return fullSheetDetent
    79→        }
    80→    }
    81→
    82→    /// Map presentation detent back to state.
    83→    static func state(
    84→        for detent: PresentationDetent,
    85→        compactDetent: PresentationDetent,
    86→        fullSheetDetent: PresentationDetent = .large
    87→    ) -> ContactIslandState {
    88→        if detent == compactDetent {
    89→            return .compact
    90→        }
    91→        if detent == fullSheetDetent || detent == .large {
    92→            return .fullSheet
    93→        }
    94→        return .compact
    95→    }
    96→
    97→    /// Ratio caps for dynamic detents.
    98→    static let fullSheetMaxRatio: CGFloat = 0.82
    99→
   100→    /// Dynamic detent heights based on screen height.
   101→    static func detentHeights(screenHeight: CGFloat) -> (compact: CGFloat, fullSheet: CGFloat) {
   102→        let compact = DesignTokens.ContactIsland.compactHeight
   103→        guard screenHeight > 0 else {
   104→            return (compact, DesignTokens.ContactIsland.fullSheetHeight)
   105→        }
   106→
   107→        let full = screenHeight * fullSheetMaxRatio
   108→
   109→        return (compact, full)
   110→    }
   111→
   112→    /// Dynamic height for a state based on screen height.
   113→    static func height(for state: ContactIslandState, screenHeight: CGFloat) -> CGFloat {
   114→        let heights = detentHeights(screenHeight: screenHeight)
   115→        switch state {
   116→        case .compact:
   117→            return heights.compact
   118→        case .fullSheet:
   119→            return heights.fullSheet
   120→        }
   121→    }
   122→}
   123→
   124→/// Spring animation configuration for ContactIsland transitions
   125→enum ContactIslandAnimation {
   126→    static let spring = Animation.spring(response: 0.35, dampingFraction: 0.75)
   127→    static let quickSpring = Animation.spring(response: 0.25, dampingFraction: 0.8)
   128→}
   129→

